import Bio
from Bio.Seq import Seq
dna = Seq("")
g_count = dna.count("G")
c_count = dna.count("C")

total_length = len(dna)

gc_content = ((g_count+c_count)/total_length)*100

print("Length: ", total_length)
print("G Count: ", g_count)
print("C Count: ", c_count)
print("GC Content: ", gc_content,"%")
